import React from "react";

const PdfViewer = ({ pdfUrl }) => {
  console.log("PDF URL received:", pdfUrl); // This will help us debug

  if (!pdfUrl) {
    return null;
  }

  return (
    <div className="pdf-viewer-container">
      <iframe
        src={`http://localhost:8000/pdfs/${pdfUrl}`}
        width="100%"
        height="100%"
        style={{ border: "none", minHeight: "800px" }}
        title="PDF Viewer"
      />
    </div>
  );
};

export default PdfViewer;
